import{_ as e,c as s,o as n,ae as a}from"./chunks/framework.Dh1jimFm.js";const l="/static/1.svg",f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"client-doc/core/wpsPreview.md","filePath":"client-doc/core/wpsPreview.md","lastUpdated":1770358354000}'),i={name:"client-doc/core/wpsPreview.md"};function p(d,t,o,r,g,c){return n(),s("div",null,t[0]||(t[0]=[a('<h3 id="wps文件预览" tabindex="-1">wps文件预览 <a class="header-anchor" href="#wps文件预览" aria-label="Permalink to &quot;wps文件预览&quot;">​</a></h3><p>在上传需要预览的文件后 由前端传入文件id、文件名 调用获取预览链接接口 返回预览链接</p><p>涉及到的外部能力：wps中台获取预览链接接口</p><h4 id="普通预览-高清预览接入流程" tabindex="-1">普通预览/高清预览接入流程 <a class="header-anchor" href="#普通预览-高清预览接入流程" aria-label="Permalink to &quot;普通预览/高清预览接入流程&quot;">​</a></h4><p>前置步骤： 完成证书授权,获取access_key（简称ak）和secret_key（简称sk）</p><p>第一步：<a href="http://10.10.3.23/c/manage/docs#/appDocs/docs.open.document/%E6%9C%8D%E5%8A%A1%E7%AB%AFAPI/%E5%9C%A8%E7%BA%BF%E9%A2%84%E8%A7%88/%E5%9B%9E%E8%B0%83API%E5%88%97%E8%A1%A8" target="_blank" rel="noreferrer">回调API实现</a></p><p>第二步：<a href="http://10.10.3.23/c/manage/docs#/appDocs/docs.open.document/%E4%BA%A7%E5%93%81%E6%A6%82%E8%BF%B0/%E5%AF%B9%E6%8E%A5%E8%AF%B4%E6%98%8E/%E7%B3%BB%E7%BB%9F%E5%90%8E%E5%8F%B0" target="_blank" rel="noreferrer">设置回调地址</a></p><p>第三步：获取在线预览链接</p><p><img src="'+l+`" alt="流程图"></p><h4 id="获取预览链接" tabindex="-1">获取预览链接 <a class="header-anchor" href="#获取预览链接" aria-label="Permalink to &quot;获取预览链接&quot;">​</a></h4><h4 id="请求说明" tabindex="-1">请求说明 <a class="header-anchor" href="#请求说明" aria-label="Permalink to &quot;请求说明&quot;">​</a></h4><p><strong>请求地址：</strong> 配置域名+<code>/open</code>+<code>/api/preview/v1/files/{file_id}/link</code><strong>请求方法：</strong> GET <strong>签名方式：</strong> <a href="http://10.10.3.23/c/manage/docs#/appDocs/docs.open.document/%E6%9C%8D%E5%8A%A1%E7%AB%AFAPI/WPS-4%E7%AD%BE%E5%90%8D" target="_blank" rel="noreferrer">WPS-4签名</a>/<a href="http://10.10.3.23/c/manage/docs#/appDocs/docs.open.document/%E6%9C%8D%E5%8A%A1%E7%AB%AFAPI/WPS-4-GM%E7%AD%BE%E5%90%8D" target="_blank" rel="noreferrer">WPS-4-GM签名</a></p><h4 id="请求头-header" tabindex="-1">请求头（Header） <a class="header-anchor" href="#请求头-header" aria-label="Permalink to &quot;请求头（Header）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">Content-Type</td><td style="text-align:left;">是</td><td style="text-align:left;">固定为: <code>application/json</code></td></tr><tr><td style="text-align:left;">Wps-Docs-Date</td><td style="text-align:left;">是</td><td style="text-align:left;">取当前时间, 示例: <code>Wed, 23 Jan 2013 06:43:08 GMT</code></td></tr><tr><td style="text-align:left;">Wps-Docs-Authorization</td><td style="text-align:left;">是</td><td style="text-align:left;">计算方法参考<a href="http://10.10.3.23/docs.open.document/%E6%9C%8D%E5%8A%A1%E7%AB%AFAPI/WPS-4%E7%AD%BE%E5%90%8D" target="_blank" rel="noreferrer">签名说明</a></td></tr></tbody></table><h4 id="查询参数-path" tabindex="-1">查询参数(Path) <a class="header-anchor" href="#查询参数-path" aria-label="Permalink to &quot;查询参数(Path)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">类型</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">file_id</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">文件id,长度不超过64位</td></tr></tbody></table><h4 id="查询参数-query" tabindex="-1">查询参数(Query) <a class="header-anchor" href="#查询参数-query" aria-label="Permalink to &quot;查询参数(Query)&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">类型</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">type</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">文件格式，可选值： <code>w</code>:文字文件 <code>s</code>:表格文件 <code>p</code>:演示文件 <code>f</code>:PDF文件 <code>x</code>:文件类型（图片、压缩包、md、eml、代码、其他），传空时默认为该类型</td></tr><tr><td style="text-align:left;">preview_mode</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;"><strong>适用版本 &gt;= v6.0.2207.20220729</strong> 预览模式，可选值： <code>high_definition</code>:高清预览 <code>ordinary</code>:普通预览 <code>cache</code>:缓存预览 <code>official</code>:公文极速预览（&gt;=v6.1.2302.20230220）不传默认official</td></tr><tr><td style="text-align:left;">wpsPreview</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;">高清预览支持控制修订痕迹、评论是否显示等参数。高清预览参数wpsPreview=1111111从左到右依次代表： 第0位：格式修订：0不显示；1：显示 第1位：插入和删除：0不显示；1：显示 第2位：评论 0不显示；1：显示 第3位：以嵌入模式显示修订 第4位：以气泡模式显示修订 第5位：0不显示标记；1：显示标记 第6位：0最终状态；1：原始状态 注：(第3、4位组合：01及11为批注框方式；10是嵌入方式 00是批注框显示修订者)</td></tr><tr><td style="text-align:left;">_w_tokentype</td><td style="text-align:left;">int</td><td style="text-align:left;">否</td><td style="text-align:left;"><strong>适用版本&gt;=v7.0.2309a.20230907</strong> 是否透传token，传1时透传</td></tr><tr><td style="text-align:left;">*任意参数</td><td style="text-align:left;">*任意类型</td><td style="text-align:left;">否</td><td style="text-align:left;">合作方自定义参数，要求以 <code>_w_third_</code> 作为前缀，回调时会一并返回给开发者。<code>_w_third_appid</code> 、<code>_w_third_file_id</code> 字段已被使用，对接方请合理避开。</td></tr></tbody></table><blockquote><p><strong>注意：</strong> 所有参数值必须做urlencode，例如<code>http://xxxx:xx/api/preview/v1/files/471eba5030/link?type=w&amp;_w_third_name=%E4%BC%9A%E8%AE%AE%E7%BA%AA%E8%A6%81.docx&amp;_w_third_userid=33</code></p></blockquote><h4 id="响应体-response" tabindex="-1">响应体（Response） <a class="header-anchor" href="#响应体-response" aria-label="Permalink to &quot;响应体（Response）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">类型</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">data</td><td style="text-align:left;">object</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>∟</strong> link</td><td style="text-align:left;">string</td><td style="text-align:left;">文件在线预览链接,示例：配置域名+/weboffice/office/{file_type}/{file_id}?_w_appid=11&amp;用户自定义参数 +&amp;wpsPreview=1111111&amp;simple&amp;hidecmb</td></tr><tr><td style="text-align:left;">code</td><td style="text-align:left;">integer</td><td style="text-align:left;">错误码，参照<a href="http://10.10.3.23/docs.open.document/%E6%9C%8D%E5%8A%A1%E7%AB%AFAPI/%E9%94%99%E8%AF%AF%E7%A0%81" target="_blank" rel="noreferrer">《错误码说明》</a></td></tr><tr><td style="text-align:left;">msg</td><td style="text-align:left;">string</td><td style="text-align:left;">状态信息</td></tr><tr><td style="text-align:left;">request_time</td><td style="text-align:left;">long</td><td style="text-align:left;">请求时间</td></tr><tr><td style="text-align:left;">request_id</td><td style="text-align:left;">string</td><td style="text-align:left;">请求标识id</td></tr><tr><td style="text-align:left;">response_time</td><td style="text-align:left;">long</td><td style="text-align:left;">响应时间</td></tr></tbody></table><h4 id="响应体示例" tabindex="-1">响应体示例 <a class="header-anchor" href="#响应体示例" aria-label="Permalink to &quot;响应体示例&quot;">​</a></h4><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;data&quot;:{</span></span>
<span class="line"><span>        &quot;link&quot;:&quot;http://yun.test.cn/weboffice/office/w/777e2226783346c592f41d4b1362?_w_appid=AKVyEoaNGupKxTOA&amp;wpsPreview=1111111&amp;simple&amp;hidecmb&quot;</span><span>             //文件在线预览链接</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>    &quot;code&quot;: 200,</span></span>
<span class="line"><span>    &quot;msg&quot;: &quot;success&quot;,</span></span>
<span class="line"><span>    &quot;request_time&quot;: 1653272135097,</span></span>
<span class="line"><span>    &quot;request_id&quot;: &quot;1416070c674445b866fe&quot;,</span></span>
<span class="line"><span>    &quot;response_time&quot;: 1653272135101</span></span>
<span class="line"><span>}</span></span></code></pre></div><blockquote><p><strong>特别说明</strong>： 预览链接中重要参数含义：&amp;simple&amp;hidecmb表示隐藏菜单栏</p></blockquote><blockquote><p>公文极速预览链接中重要参数含义：&amp;revisionView=0表示显示标记最终状态；&amp;revisionView=1表示最终状态；&amp;revisionView=2表示显示标记的原始状态；&amp;revisionView=3表示原始状态；</p></blockquote><blockquote><p>压缩包预览默认当前页面预览。可拼接&amp;isNew=true以此支持新页面打开压缩包内的文件进行预览。若需屏蔽压缩包内的部分文件格式，可拼接&amp;ignore参数，如&amp;ignore=doc,Docx，ignore参数是由文件后缀组成，表示需要屏蔽doc、docx格式类型，不区分大小写。</p></blockquote><blockquote><p>注意：使用缓存预览无法高清预览，不要拼接高清预览参数 缓存预览不支持pdf纯图预览</p></blockquote><p><strong>代码实现：</strong></p><p>java</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>public AjaxResult getFilePreviewLink(SysMinioFile sysMinioFile) {</span></span>
<span class="line"><span>    try {</span></span>
<span class="line"><span>        if (ObjectUtil.isEmpty(sysMinioFile) || ObjectUtil.isEmpty(sysMinioFile.getId()) || ObjectUtil.isEmpty(sysMinioFile.getFileName())) {</span></span>
<span class="line"><span>            return AjaxResult.success();</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        var type = &quot;x&quot;;</span></span>
<span class="line"><span>        var anEnum = FileEnum.getByCode(getEndWith(sysMinioFile.getFileName()));</span></span>
<span class="line"><span>        if (ObjectUtil.isNotEmpty(anEnum)) {</span></span>
<span class="line"><span>            type = switch (anEnum) {</span></span>
<span class="line"><span>                case DOC, DOCX -&gt; &quot;w&quot;;</span></span>
<span class="line"><span>                case XLS, XLSX -&gt; &quot;s&quot;;</span></span>
<span class="line"><span>                case PDF -&gt; &quot;f&quot;;</span></span>
<span class="line"><span>                case PPT -&gt; &quot;p&quot;;</span></span>
<span class="line"><span>                default -&gt; &quot;x&quot;;</span></span>
<span class="line"><span>            };</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        var finalType = type;</span></span>
<span class="line"><span>        var params = new HashMap&lt;String, String&gt;() {{</span></span>
<span class="line"><span>            put(&quot;type&quot;, finalType);</span></span>
<span class="line"><span>            put(&quot;preview_mode&quot;, &quot;ordinary&quot;);</span></span>
<span class="line"><span>            put(&quot;_w_third_id&quot;, String.valueOf(sysMinioFile.getId()));</span></span>
<span class="line"><span>            put(&quot;_w_third_client_id&quot;, clientId);</span></span>
<span class="line"><span>            put(&quot;_w_third_user_name&quot;, SecurityUtils.getUsername());</span></span>
<span class="line"><span>        }};</span></span>
<span class="line"><span>        var uriWithQuerystring = buildEncodeUri(sysMinioFile, params);</span></span>
<span class="line"><span>        log.info(&quot;调用文档中台获取预览链接入参:{}&quot;, uriWithQuerystring);</span></span>
<span class="line"><span>        var signature = new WPS4Signature(accessKey, secretKey);</span></span>
<span class="line"><span>        var headers = signature.getSignatureHeaders2(&quot;GET&quot;, uriWithQuerystring, &quot;&quot;, &quot;application/json&quot;);</span></span>
<span class="line"><span>        var response = HttpUtil.doGet(officeHost.concat(&quot;/open&quot;).concat(&quot;/api/preview/v1/files/&quot;).concat(String.valueOf(sysMinioFile.getId()).concat(&quot;/link&quot;)), (status, res) -&gt; res, params, headers);</span></span>
<span class="line"><span>        if (ObjectUtil.isEmpty(response)) {</span></span>
<span class="line"><span>            return AjaxResult.error(&quot;调用文档中台异常!&quot;);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        log.info(&quot;调用文档中台获取预览链接出参:{}&quot;, response);</span></span>
<span class="line"><span>        return AjaxResult.success(JSONObject.parseObject(response));</span></span>
<span class="line"><span>    } catch (Exception e) {</span></span>
<span class="line"><span>        e.printStackTrace();</span></span>
<span class="line"><span>        return AjaxResult.error(&quot;调用文档中台异常!&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>获取预览链接后由前端打开新窗口或嵌入</p><h3 id="获取文件信息-wps中台回调" tabindex="-1">获取文件信息（wps中台回调） <a class="header-anchor" href="#获取文件信息-wps中台回调" aria-label="Permalink to &quot;获取文件信息（wps中台回调）&quot;">​</a></h3><p>页面渲染文件时需通过此回调获取文件元数据，包括当前文件信息、当前用户信息、操作权限信息</p><blockquote><p>文档打开时会进行多次回调：由于文档加载是动态逐页加载渲染，加载过程中需要向业务系统鉴权以为保证文档安全。 若需降低回调频率，需执行以下操作： 1.服务端全局配置开启缓存 2.TOKEN访问：通过JSSDK设置TOKEN。此处TOKEN访问是因为file/info数据根据不同用户请求到的信息不一致，若不根据TOKEN进行缓存数据会导致越权行为。 3.file/info回调接口返回缓存时间</p></blockquote><h4 id="回调说明" tabindex="-1">回调说明 <a class="header-anchor" href="#回调说明" aria-label="Permalink to &quot;回调说明&quot;">​</a></h4><p><strong>回调地址：</strong> 回调地址 + uri（默认/v1/3rd/file/info）</p><p><strong>请求方法：</strong> GET</p><p><strong>签名方式：</strong> 无</p><h4 id="请求头-header-1" tabindex="-1">请求头（Header） <a class="header-anchor" href="#请求头-header-1" aria-label="Permalink to &quot;请求头（Header）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">X-Weboffice-File-Id</td><td style="text-align:left;">是</td><td style="text-align:left;">文件id,字符串长度不超过64位</td></tr><tr><td style="text-align:left;">X-Wps-Weboffice-Token</td><td style="text-align:left;">否</td><td style="text-align:left;">开发者通过<a href="https://wwo.wps.cn/docs/front-end/" target="_blank" rel="noreferrer">JSSDK设置用于用户鉴权TOKEN</a></td></tr></tbody></table><h4 id="查询参数-query-1" tabindex="-1">查询参数（Query） <a class="header-anchor" href="#查询参数-query-1" aria-label="Permalink to &quot;查询参数（Query）&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">参数类型</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">*（任意参数）</td><td style="text-align:left;">*（任意类型）</td><td style="text-align:left;">否</td><td style="text-align:left;">在获取预览链接时按需求传入的所有自定义参数</td></tr></tbody></table><h4 id="响应体-response-1" tabindex="-1">响应体（Response） <a class="header-anchor" href="#响应体-response-1" aria-label="Permalink to &quot;响应体（Response）&quot;">​</a></h4><h5 id="正常返回" tabindex="-1">正常返回 <a class="header-anchor" href="#正常返回" aria-label="Permalink to &quot;正常返回&quot;">​</a></h5><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">类型</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">file</td><td style="text-align:left;">object</td><td style="text-align:left;">是</td><td style="text-align:left;">文件信息</td></tr><tr><td style="text-align:left;"><strong>∟</strong> id</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">文件id,字符串长度不超过64位</td></tr><tr><td style="text-align:left;"><strong>∟</strong> name</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">文件名必须带后缀</td></tr><tr><td style="text-align:left;"><strong>∟</strong> version</td><td style="text-align:left;">integer</td><td style="text-align:left;">是</td><td style="text-align:left;">文档版本号，从1开始累加，位数小于11</td></tr><tr><td style="text-align:left;"><strong>∟</strong> size</td><td style="text-align:left;">integer</td><td style="text-align:left;">是</td><td style="text-align:left;">文档大小，单位为字节；此处需传文件真实大小，否则会出现异常</td></tr><tr><td style="text-align:left;"><strong>∟</strong> readonly</td><td style="text-align:left;">Boolean</td><td style="text-align:left;">否</td><td style="text-align:left;">readonly默认为<code>false</code> <code>true</code>开启表格筛选，支持对EXCEL表格文档筛选，但不支持对EXCEL表格文档开启多人同步筛选，该预览特性见常见问题 <code>false</code>关闭表格筛选（20220707新增）</td></tr><tr><td style="text-align:left;"><strong>∟</strong> creator</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">创建者id，字符串长度不超过32位。与user里的id一致。</td></tr><tr><td style="text-align:left;"><strong>∟</strong> create_time</td><td style="text-align:left;">integer</td><td style="text-align:left;">是</td><td style="text-align:left;">创建时间，时间戳，单位为秒。与user里的id一致。</td></tr><tr><td style="text-align:left;"><strong>∟</strong> modifier</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">修改者id，字符串长度不超过32位</td></tr><tr><td style="text-align:left;"><strong>∟</strong> modify_time</td><td style="text-align:left;">integer</td><td style="text-align:left;">是</td><td style="text-align:left;">最近修改时间，时间戳，单位为秒</td></tr><tr><td style="text-align:left;"><strong>∟</strong> download_url</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">文档下载地址</td></tr><tr><td style="text-align:left;"><strong>∟</strong> preview_pages</td><td style="text-align:left;">integer</td><td style="text-align:left;">是</td><td style="text-align:left;">普通预览模式下可限制预览页数（不超过5000） previewPages 默认值为 0，不限制预览页数； previewPages &gt;= 1 时，限制生效，限制的页数为 previewpages 字段的值</td></tr><tr><td style="text-align:left;"><strong>∟</strong> user_acl</td><td style="text-align:left;">object</td><td style="text-align:left;">否</td><td style="text-align:left;">用户权限</td></tr><tr><td style="text-align:left;"><strong>∟</strong> rename</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">重命名权限，1为打开该权限，0为关闭该权限，默认为0</td></tr><tr><td style="text-align:left;"><strong>∟</strong> history</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">历史文件打开权限，1为打开该权限，0为关闭该权限，默认为1</td></tr><tr><td style="text-align:left;"><strong>∟</strong> copy</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">复制权限，1为打开该权限，0为关闭该权限，默认为1</td></tr><tr><td style="text-align:left;"><strong>∟</strong> export</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">导出权限，1为打开该权限，0为关闭该权限，默认为1</td></tr><tr><td style="text-align:left;"><strong>∟</strong> print</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">打印权限，1为打开该权限，0为关闭该权限，默认为1</td></tr><tr><td style="text-align:left;"><strong>∟</strong> watermark</td><td style="text-align:left;">object</td><td style="text-align:left;">否</td><td style="text-align:left;">水印参数</td></tr><tr><td style="text-align:left;"><strong>∟</strong> type</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">水印类型， 0为无水印； 1为文字水印</td></tr><tr><td style="text-align:left;"><strong>∟</strong> value</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;">文字水印的文字，支持通过<code>\\r\\n</code>换行，支持emoji表情 当type为1时此字段必选</td></tr><tr><td style="text-align:left;"><strong>∟</strong> fillstyle</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;">水印的颜色（含透明度），非必选，有默认值。格式为：<code>rgba( 192, 192, 192, 0.6 )</code></td></tr><tr><td style="text-align:left;"><strong>∟</strong> font</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;">水印的字体，非必选，有默认值，格式为<code>bold 20px Serif</code></td></tr><tr><td style="text-align:left;"><strong>∟</strong> rotate</td><td style="text-align:left;">float</td><td style="text-align:left;">否</td><td style="text-align:left;">水印的旋转度(弧度)，非必选，有默认值，默认为-0.7853982</td></tr><tr><td style="text-align:left;"><strong>∟</strong> horizontal</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">水印水平间距，非必选，有默认值，默认为50</td></tr><tr><td style="text-align:left;"><strong>∟</strong> vertical</td><td style="text-align:left;">integer</td><td style="text-align:left;">否</td><td style="text-align:left;">水印垂直间距，非必选，有默认值，默认为100</td></tr><tr><td style="text-align:left;"><strong>∟</strong> attrs</td><td style="text-align:left;">object</td><td style="text-align:left;">否</td><td style="text-align:left;">附加参数，v6.0.2209.20220920新增</td></tr><tr><td style="text-align:left;"><strong>∟</strong> cachetime</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;">单位秒，取值范围为1-300，超过300秒不会缓存回调信息，此字段需服务端全局配置开启缓存，且需要使用token访问预览链接</td></tr><tr><td style="text-align:left;">user</td><td style="text-align:left;">object</td><td style="text-align:left;">是</td><td style="text-align:left;">用户信息</td></tr><tr><td style="text-align:left;"><strong>∟</strong> id</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">用户id，长度不超过32位，与creator、modifier一致</td></tr><tr><td style="text-align:left;"><strong>∟</strong> name</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">用户名称</td></tr><tr><td style="text-align:left;"><strong>∟</strong> permission</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">用户操作权限，预览固定为read</td></tr></tbody></table><h5 id="正常返回示例" tabindex="-1">正常返回示例 <a class="header-anchor" href="#正常返回示例" aria-label="Permalink to &quot;正常返回示例&quot;">​</a></h5><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;file&quot;: {</span></span>
<span class="line"><span>        &quot;id&quot;: &quot;132aa30a87064&quot;, </span></span>
<span class="line"><span>        &quot;name&quot;: &quot;example.doc&quot;, </span></span>
<span class="line"><span>        &quot;version&quot;: 1, </span></span>
<span class="line"><span>        &quot;size&quot;: 200, </span></span>
<span class="line"><span>        &quot;creator&quot;: &quot;id1000&quot;, </span></span>
<span class="line"><span>        &quot;create_time&quot;: 1136185445, </span></span>
<span class="line"><span>        &quot;modifier&quot;: &quot;id1000&quot;, </span></span>
<span class="line"><span>        &quot;modify_time&quot;: 1551409818, </span></span>
<span class="line"><span>        &quot;download_url&quot;: &quot;http://www.xxx.cn/v1/file?fid=f132aa30a87064&quot;, </span></span>
<span class="line"><span>        &quot;preview_pages&quot;: 3, </span></span>
<span class="line"><span>        &quot;user_acl&quot;: {</span></span>
<span class="line"><span>            &quot;rename&quot;: 1, </span></span>
<span class="line"><span>            &quot;history&quot;: 1, </span></span>
<span class="line"><span>            &quot;copy&quot;: 1, </span></span>
<span class="line"><span>            &quot;export&quot;: 1, </span></span>
<span class="line"><span>            &quot;print&quot;: 1</span></span>
<span class="line"><span>        }, </span></span>
<span class="line"><span>        &quot;watermark&quot;: {</span></span>
<span class="line"><span>            &quot;type&quot;: 1, </span></span>
<span class="line"><span>            &quot;value&quot;: &quot;禁止传阅\\r\\nwps-1000&quot;, </span></span>
<span class="line"><span>            &quot;fillstyle&quot;: &quot;rgba( 192, 192, 192, 0.6 )&quot;, </span></span>
<span class="line"><span>            &quot;font&quot;: &quot;bold 20px Serif&quot;, </span></span>
<span class="line"><span>            &quot;rotate&quot;: -0.7853982, </span></span>
<span class="line"><span>            &quot;horizontal&quot;: 50, </span></span>
<span class="line"><span>            &quot;vertical&quot;: 100</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        &quot;attrs&quot;: {</span></span>
<span class="line"><span>            &quot;cachetime&quot;: &quot;100&quot; </span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }, </span></span>
<span class="line"><span>    &quot;user&quot;: {</span></span>
<span class="line"><span>        &quot;id&quot;: &quot;id1000&quot;, </span></span>
<span class="line"><span>        &quot;name&quot;: &quot;wps-1000&quot;, </span></span>
<span class="line"><span>        &quot;permission&quot;: &quot;read&quot;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><h5 id="异常返回" tabindex="-1">异常返回 <a class="header-anchor" href="#异常返回" aria-label="Permalink to &quot;异常返回&quot;">​</a></h5><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">类型</th><th style="text-align:left;">是否必填</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">code</td><td style="text-align:left;">integer</td><td style="text-align:left;">是</td><td style="text-align:left;">错误码，详细见<a href="http://10.10.3.23/docs.open.document/%E6%9C%8D%E5%8A%A1%E7%AB%AFAPI/%E9%94%99%E8%AF%AF%E7%A0%81" target="_blank" rel="noreferrer">《回调错误码》</a></td></tr><tr><td style="text-align:left;">message</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">错误提示</td></tr><tr><td style="text-align:left;">details</td><td style="text-align:left;">string</td><td style="text-align:left;">是</td><td style="text-align:left;">错误提示详细信息</td></tr><tr><td style="text-align:left;">hint</td><td style="text-align:left;">string</td><td style="text-align:left;">否</td><td style="text-align:left;">自定义错误信息，当code为40007错误码时必填</td></tr></tbody></table><h5 id="异常返回示例" tabindex="-1">异常返回示例 <a class="header-anchor" href="#异常返回示例" aria-label="Permalink to &quot;异常返回示例&quot;">​</a></h5><p>json</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;code&quot;: 40005,</span></span>
<span class="line"><span>  &quot;message&quot;: &quot;InvalidArgument&quot;,</span></span>
<span class="line"><span>  &quot;details&quot;: &quot;参数错误&quot;,</span></span>
<span class="line"><span>  &quot;hint&quot;: &quot;自定义错误提示&quot;   </span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>代码实现：</strong></p><p>java</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/**</span></span>
<span class="line"><span> * @Description 文件中台回调接口</span></span>
<span class="line"><span> * @MethodName fileInfo</span></span>
<span class="line"><span> * @Author Liheng</span></span>
<span class="line"><span> * @Date 2025/07/23 09:44:20</span></span>
<span class="line"><span> * @Param fileId</span></span>
<span class="line"><span> */</span></span>
<span class="line"><span>@Override</span></span>
<span class="line"><span>public Object fileInfo(String fileId, String userName) {</span></span>
<span class="line"><span>    try {</span></span>
<span class="line"><span>        if (ObjectUtil.isEmpty(fileId)) {</span></span>
<span class="line"><span>            return new HashMap&lt;&gt;();</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        log.info(&quot;文件中台回调接口开始,入参：{},{}&quot;, fileId, userName);</span></span>
<span class="line"><span>        var fileInfo = sysFileService.getById(fileId);</span></span>
<span class="line"><span>        if (ObjectUtil.isEmpty(fileInfo) || ObjectUtil.isEmpty(fileInfo.getFileUrl())) {</span></span>
<span class="line"><span>            log.info(&quot;文件中台回调接口获取文件为空!{}&quot;, fileId);</span></span>
<span class="line"><span>            return new HashMap&lt;&gt;();</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>        var fileInputStream = StreamUtil.getInputStream(fileInfo.getFileUrl());</span></span>
<span class="line"><span>        var fileSize = getSize(fileInputStream);</span></span>
<span class="line"><span>        var resultMap = new HashMap&lt;String, Object&gt;() {{</span></span>
<span class="line"><span>            put(&quot;file&quot;, new HashMap&lt;String, Object&gt;() {{</span></span>
<span class="line"><span>                put(&quot;id&quot;, fileId);</span></span>
<span class="line"><span>                put(&quot;name&quot;, fileInfo.getFileName());</span></span>
<span class="line"><span>                put(&quot;version&quot;, 1);</span></span>
<span class="line"><span>                put(&quot;size&quot;, fileSize);</span></span>
<span class="line"><span>                put(&quot;creator&quot;, &quot;admin&quot;);</span></span>
<span class="line"><span>                put(&quot;create_time&quot;, DateUtil.date().getTime() / 1000);</span></span>
<span class="line"><span>                put(&quot;modifier&quot;, &quot;admin&quot;);</span></span>
<span class="line"><span>                put(&quot;modify_time&quot;, DateUtil.date().getTime() / 1000);</span></span>
<span class="line"><span>                put(&quot;download_url&quot;, fileInfo.getFileUrl());</span></span>
<span class="line"><span>                put(&quot;preview_pages&quot;, 0);</span></span>
<span class="line"><span>            }});</span></span>
<span class="line"><span>            put(&quot;user&quot;, new HashMap&lt;String, Object&gt;() {{</span></span>
<span class="line"><span>                put(&quot;id&quot;, fileId);</span></span>
<span class="line"><span>                put(&quot;name&quot;, &quot;admin&quot;);</span></span>
<span class="line"><span>                put(&quot;permission&quot;, &quot;read&quot;);</span></span>
<span class="line"><span>            }});</span></span>
<span class="line"><span>        }};</span></span>
<span class="line"><span>        log.info(&quot;文件中台回调接口结束,出参:{}&quot;, JSONUtil.toJsonStr(resultMap));</span></span>
<span class="line"><span>        return JSONUtil.parseObj(resultMap);</span></span>
<span class="line"><span>    } catch (Exception e) {</span></span>
<span class="line"><span>        e.printStackTrace();</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    return new HashMap&lt;&gt;();</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,57)]))}const y=e(i,[["render",p]]);export{f as __pageData,y as default};
